import { useFormik } from "formik";
import { LeagueTable } from "../../objects/league-table";
import { PostLeagueTableResult } from "../../services/league-table-service";
import { useEffect, useState } from "react";
import { GetTeams } from "../../services/teams-service";
import { Team } from "../../objects/team"
import { Season } from "../../objects/season";
import { GetSeasons } from "../../services/season-service";
import TextField from "../../atoms/textfield/textfield";
import { Fixture } from "../../objects/fixture";
import { useNavigate } from "react-router-dom";
import { DatePicker } from "@mui/x-date-pickers";
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs'
import dayjs, {Dayjs} from 'dayjs';


const AdminFixture = ()  =>
{
    const navigate = useNavigate();  
    const [teams, setTeams] = useState<Team []>();
    const [seasons, setSeasons] = useState<Season []>();
    
    useEffect(() => {
        GetTeams().then((data) => setTeams(data));   
        GetSeasons().then((data) => setSeasons(data));
    },[])

    const formik = useFormik({
        initialValues :{ homeTeam: "", awayTeam: "", homeTeamScore :0, awayTeamScore :0, date: dayjs(), result : 0, location : 0,  season: 6, type : 0, pts: 0,  glsFor : 0,glsA : 0 },
        onSubmit : values => {
            const fixture : Fixture = {id : 0, homeTeam: values.homeTeam, awayTeam: values.awayTeam, homeTeamScore : values.homeTeamScore, awayTeamScore : values.awayTeamScore, date: values.date, result : values.result, location : values.location,  seasonId: values.season, type : values.type, pts: values.pts,  glsFor : values.glsFor, glsA : values.glsA}
            //PostLeagueTableResult(fixture).then(formik.resetForm);
        }
    });

    return(
        <>       
            <div>           
                <form onSubmit={formik.handleSubmit}>
                    <div className="row">
                        <div className="col-2">
                            <label htmlFor="season" className="col-form-label">Season
                                <select id="season" className="form-control" {...formik.getFieldProps("season")}> 
                                    <option value="">Select a season</option>
                                    {seasons?.map(option => (
                                        <option key={option.id} value={option.id}>U{option.ageGroup + " " + option.endYear + " (Div " + option.division + ")"}</option>
                                    ))}
                                </select>
                            </label>
                        </div>   
                        <div className="col-2">
                            <DatePicker defaultValue={dayjs('2022-04-17')} label="Date of match" {...formik.getFieldProps("date")}/>
                        </div>
                        <div className="col-2">
                            <label htmlFor="homeTeam" className="col-form-label">Home Team
                                <select id="homeTeam" className="form-control" {...formik.getFieldProps("homeTeam")}> 
                                    <option value="">Select the home team</option>
                                    {teams?.map(option => (
                                        <option key={option.id} value={option.id}>{option.name}</option>
                                    ))}
                                </select>
                            </label>
                        </div>
                        <div className="col-2">
                            <TextField label="Home Team Score" name="homeTeamScore" value="0" formik={formik}/>
                        </div>
                        <div className="col-2">
                            <label htmlFor="awayTeam" className="col-form-label">Away Team
                                <select id="awayTeam" className="form-control" {...formik.getFieldProps("awayTeam")}> 
                                    <option value="">Select the away team</option>
                                    {teams?.map(option => (
                                        <option key={option.id} value={option.id}>{option.name}</option>
                                    ))}
                                </select>
                            </label>
                        </div>
                        <div className="col-2">
                            <TextField label="Away Team Score" name="awayTeamScore" value="0" formik={formik}/>
                        </div>
                        
                        <div className="row">
                            <div className="col-2">
                                <TextField label="Won" name="won" value="0" formik={formik}/>
                            </div>
                            <div className="col-2">
                                <TextField label="Lost" name="lost" value="0" formik={formik}/>                        
                            </div>   
                            <div className="col-2">
                                <TextField label="Drawn" name="drawn" value="0" formik={formik}/>                        
                            </div>                      
                            <div className="col-2">
                                <TextField label="Gls For" name="glsFor" value="0" formik={formik}/>                        
                            </div>   
                            <div className="col-2">
                                <TextField label="Gls A" name="glsA" value="0" formik={formik}/>
                            </div>  
                        </div>
                        <div className="row">
                            <div className="col-2">
                                <button className="btn btn-secondary" onClick={()=> navigate('/Admin')}>Back</button>    
                                <button className="btn btn-primary" type="submit">Go</button>    
                            </div>
                        </div> 
                    </div>
                </form>            
            </div>
        </>
    );
}

export default AdminFixture;
